use clap::Command;
use color_eyre::Result;

// Module declarations - these are auto-generated by build.rs
// To add a new applet, just create the .rs file in this directory
// The build script will automatically discover it and generate the declarations
// This file is generated in src/applets/ so modules can be found
include!("_modules_gen.rs");

/// Macro to register applet commands
/// Auto-generated from applets directory at build time
macro_rules! register_applets {
    ($(($module:ident, $cmd_name:literal)),* $(,)?) => {
        /// Get all busybox subcommands
        pub fn busybox_subcommands() -> Vec<Command> {
            vec![
                $($module::command(),)*
            ]
        }

        /// Execute a built-in command by name and matches
        /// Returns an error if the command is not a built-in command
        pub fn exec_builtin_command(cmd_name: &str, matches: &clap::ArgMatches) -> Result<()> {
            match cmd_name {
                $(
                    $cmd_name => {
                        let options = $module::parse_options(matches)?;
                        $module::run(options)
                    }
                )*
                _ => {
                    Err(color_eyre::eyre::eyre!("Unknown built-in command: {}", cmd_name))
                }
            }
        }
    };
}

// Include auto-generated registrations
// This file is generated by build.rs from files in src/applets/
include!(concat!(env!("OUT_DIR"), "/applets_modules.rs"));
